object ExtendnBinaryLengthUDF extends Serializable {

import differenceScripts.NBinaryUtility
import org.apache.spark.sql.{DataFrame,Dataset}
import scala.collection.mutable.ArrayBuffer
import java.math.BigDecimal
import org.apache.spark.sql.types.DecimalType
import spark.implicits._

def extendNBinary(mQuery:muFields): muFieldsELength = {

  val length =  NBinaryUtility.sizeMu(NBinaryUtility.arrayStringToIntegerArrayList(mQuery.nBinary))

  val s=  muFieldsELength(mQuery.value,mQuery.d,mQuery.size,mQuery.n,mQuery.nBinary,length)
//  println(mQuery.nBinary+" "+ length  +"\n")
  s
}

def main(args:Array[String]) {

import org.apache.spark.sql.DataFrame
val df= z.get(args(0)).asInstanceOf[DataFrame]
spark.udf.register("eLength", extendNBinary _)

val ds: Dataset[muFields] = df.as[muFields]
val dss=ds.map{f => extendNBinary(muFields(f.value,f.d,f.size,f.n,f.nBinary)) }
z.put(args(1),dss)
dss.show(false)
}
}

